+"use client";
+
+import { FormEvent, useState } from "react";
+import { AppShell } from "@/components/app-shell";
+import { api, setAuthToken } from "@/lib/api";
+
+type Role = "customer" | "worker" | "admin";
+
+export default function HomePage() {
+  const [role, setRole] = useState<Role>("customer");
+  const [token, setToken] = useState<string>("");
+  const [result, setResult] = useState<string>("No API call yet.");
+
+  async function registerAndLogin(e: FormEvent<HTMLFormElement>) {
+    e.preventDefault();
+    const form = new FormData(e.currentTarget);
+    const email = String(form.get("email"));
+    const password = String(form.get("password"));
+    const full_name = String(form.get("full_name"));
+    try {
+      const registerRes = await api.post("/auth/register", { email, password, full_name, role, city: "Indore" });
+      const authToken = registerRes.data.access_token as string;
+      setToken(authToken);
+      setAuthToken(authToken);
+      setResult("Authenticated successfully.");
+    } catch {
+      const loginRes = await api.post("/auth/login", { email, password });
+      const authToken = loginRes.data.access_token as string;
+      setToken(authToken);
+      setAuthToken(authToken);
+      setResult("Logged in with existing account.");
+    }
+  }
+
+  async function callAIChat() {
+    if (!token) return setResult("Login first.");
+    const res = await api.get("/ai/chat", { params: { message: "Need plumber for pipe leakage" } });
+    setResult(`AI: ${res.data.reply}`);
+  }
+
+  async function fetchJobs() {
+    if (!token) return setResult("Login first.");
+    const res = await api.get("/jobs");
+    setResult(`Jobs found: ${res.data.length}`);
+  }
+
+  return (
+    <AppShell>
+      <div className="grid gap-6 md:grid-cols-2">
+        <section className="rounded-xl border border-slate-800 bg-slate-900 p-5">
+          <h2 className="mb-4 text-xl font-semibold">SaaS Auth Gateway</h2>
+          <form onSubmit={registerAndLogin} className="space-y-3">
+            <input name="full_name" placeholder="Full name" className="w-full rounded bg-slate-800 p-2" />
+            <input name="email" placeholder="Email" className="w-full rounded bg-slate-800 p-2" />
+            <input name="password" type="password" placeholder="Password" className="w-full rounded bg-slate-800 p-2" />
+            <select value={role} onChange={(e) => setRole(e.target.value as Role)} className="w-full rounded bg-slate-800 p-2">
+              <option value="customer">customer</option>
+              <option value="worker">worker</option>
+              <option value="admin">admin</option>
+            </select>
+            <button className="rounded bg-indigo-600 px-4 py-2">Register / Login</button>
+          </form>
+        </section>
+
+        <section className="rounded-xl border border-slate-800 bg-slate-900 p-5">
+          <h2 className="mb-4 text-xl font-semibold">AI + Workflow Demo</h2>
+          <div className="space-x-3">
+            <button onClick={callAIChat} className="rounded bg-emerald-600 px-4 py-2">AI Chat</button>
+            <button onClick={fetchJobs} className="rounded bg-sky-600 px-4 py-2">Fetch Jobs</button>
+          </div>
+          <p className="mt-4 rounded bg-slate-800 p-3 text-sm text-slate-300">{result}</p>
+        </section>
+      </div>
+    </AppShell>
+  );
+}
